import React, { useState } from "react";
import Menu from "./Menu";
import MainContent from "./MainContent";
import Footer from "./Footer";
import "./MainContent.css";
import "./Footer.css";
import "./Menu.css";

export default function App() {
  const [menuOpen, setMenuOpen] = useState(true);

  const handleToggleMenu = () => {
    setMenuOpen((open) => !open);
  };

  return (
    <div className="app-layout">
      <Menu onToggle={handleToggleMenu} isOpen={menuOpen} />
      <MainContent>
        <h1>UNIR Supplies</h1>
        <p>Bienvenido a la plataforma de suministros para tiendas UNIR.</p>
        <p>Selecciona una opción en el menú para comenzar.</p>
      </MainContent>
      <Footer />
    </div>
  );
}

import React, { useState } from "react";
import Menu from "./Menu";
import MainContent from "./MainContent";
import Footer from "./Footer";
import "./MainContent.css";
import "./Footer.css";
import "./Menu.css";

export default function App() {
  const [menuOpen, setMenuOpen] = useState(true);

  const handleToggleMenu = () => {
    setMenuOpen((open) => !open);
  };

  return (
    <div className="app-layout">
      <Menu onToggle={handleToggleMenu} isOpen={menuOpen} />
      <MainContent menuOpen={menuOpen}>
        <h1 style={{ color: '#232946' }}>UNIR Supplies</h1>
        <p>Bienvenido a la plataforma de suministros para tiendas UNIR.</p>
        <p>Selecciona una opción en el menú para comenzar.</p>
      </MainContent>
      <Footer />
    </div>
  );
}

/* Estilos para el footer */
.footer {
  background: #232946;
  color: #fff;
  text-align: center;
  padding: 18px 0;
  position: fixed;
  left: 220px;
  bottom: 0;
  width: calc(100% - 220px);
  font-size: 1rem;
  z-index: 99;
  transition: left 0.3s, width 0.3s;
}
@media (max-width: 800px) {
  .footer {
    left: 0;
    width: 100%;
  }
}

/* Estilos para el footer */
.footer {
  background: #232946;
  color: #fff;
  text-align: center;
  padding: 18px 0;
  position: fixed;
  left: 220px;
  bottom: 0;
  width: calc(100% - 220px);
  font-size: 1rem;
  z-index: 99;
  transition: left 0.3s, width 0.3s;
}
.main-content.menu-closed ~ .footer {
  left: 40px;
  width: calc(100% - 40px);
}
@media (max-width: 800px) {
  .footer {
    left: 0;
    width: 100%;
  }
}

import React from "react";
import "./Footer.css";

export default function Footer() {
  return (
    <footer className="footer">
      <p>© 2025 UNIR Supplies. Todos los derechos reservados.</p>
    </footer>
  );
}

/* Estilos para el área principal de contenido */
.main-content {
  margin-left: 220px;
  min-height: 100vh;
  background: #f4f4f4;
  padding: 32px 24px 80px 24px;
  transition: margin-left 0.3s;
}
@media (max-width: 800px) {
  .main-content {
    margin-left: 0;
    padding: 24px 8px 80px 8px;
  }
}

/* Estilos para el área principal de contenido */
.main-content {
  min-height: 100vh;
  background: #fff;
  padding: 32px 24px 80px 24px;
  transition: margin-left 0.3s;
}
.main-content.menu-open {
  margin-left: 220px;
}
.main-content.menu-closed {
  margin-left: 40px;
}
@media (max-width: 800px) {
  .main-content.menu-open,
  .main-content.menu-closed {
    margin-left: 0;
    padding: 24px 8px 80px 8px;
  }
}

import React from "react";
import "./MainContent.css";

export default function MainContent({ children }) {
  return (
    <div className="main-content">
      {children}
    </div>
  );
}

import React from "react";
import "./MainContent.css";

export default function MainContent({ children, menuOpen }) {
  return (
    <div className={`main-content ${menuOpen ? "menu-open" : "menu-closed"}`}>
      {children}
    </div>
  );
}

/* Estilos para el menú lateral y hamburguesa */
.menu {
  position: fixed;
  left: 0;
  top: 0;
  bottom: 0;
  width: 220px;
  background: #389cd1;
  color: #fff;
  transition: transform 0.3s ease, width 0.3s ease;
  z-index: 100;
  box-shadow: 2px 0 8px rgba(0,0,0,0.08);
}
.menu.closed {
  transform: translateX(-180px);
  width: 40px;
}
.menu.open {
  transform: translateX(0);
  width: 220px;
}
.hamburger {
  background: none;
  border: none;
  cursor: pointer;
  margin: 16px 0 16px 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
  width: 32px;
  height: 32px;
  z-index: 101;
}
.bar {
  display: block;
  width: 100%;
  height: 4px;
  background: #fff;
  border-radius: 2px;
  transition: all 0.3s;
}
.hamburger .bar.open:nth-child(1) {
  transform: translateY(9px) rotate(45deg);
}
.hamburger .bar.open:nth-child(2) {
  opacity: 0;
}
.hamburger .bar.open:nth-child(3) {
  transform: translateY(-9px) rotate(-45deg);
}
.menu-list {
  list-style: none;
  padding: 60px 0 0 0;
  margin: 0;
  transition: opacity 0.3s;
}
.menu.closed .menu-list {
  opacity: 0;
  pointer-events: none;
}
.menu.open .menu-list {
  opacity: 1;
  pointer-events: auto;
}
.menu-list li {
  margin: 24px 0;
  padding-left: 32px;
}
.menu-list a {
  color: #fff;
  text-decoration: none;
  font-size: 1.1rem;
  transition: color 0.2s;
}
.menu-list a:hover {
  color: #232946;
}
.menu-toggle-btn {
  position: absolute;
  left: -18px;
  top: 18px;
  width: 36px;
  height: 36px;
  background: #232946;
  color: #fff;
  border: none;
  border-radius: 50%;
  box-shadow: 0 2px 8px rgba(0,0,0,0.10);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 1.5rem;
  z-index: 102;
  transition: left 0.3s, background 0.3s;
}
.menu.closed .menu-toggle-btn {
  left: -18px;
  background: #389cd1;
  color: #fff;
}
.menu.open .menu-toggle-btn {
  left: -18px;
  background: #232946;
  color: #fff;
}
.icon-x {
  font-size: 1.5rem;
}
.icon-arrow {
  font-size: 1.5rem;
}

/* Estilos para el menú lateral fijo */
.menu {
  position: fixed;
  left: 0;
  top: 0;
  bottom: 0;
  width: 220px;
  background: #389cd1;
  color: #fff;
  z-index: 100;
  box-shadow: 2px 0 8px rgba(0,0,0,0.08);
  display: flex;
  flex-direction: column;
}
.menu-list {
  list-style: none;
  padding: 60px 0 0 0;
  margin: 0;
}
.menu-list li {
  margin: 24px 0;
  padding-left: 32px;
}
.menu-list a {
  color: #fff;
  text-decoration: none;
  font-size: 1.1rem;
  transition: color 0.2s;
}
.menu-list a:hover {
  color: #232946;
}

import React, { useState } from "react";
import "./Menu.css";

export default function Menu({ onToggle, isOpen }) {
  return (
    <>
      <nav className={`menu ${isOpen ? "open" : "closed"}`}>
        <button
          className={`menu-toggle-btn ${isOpen ? "close-btn" : "open-btn"}`}
          onClick={onToggle}
          aria-label={isOpen ? "Cerrar menú" : "Abrir menú"}
          style={{
            right: isOpen ? "-18px" : "-18px",
            left: "auto",
            transition: "top 0.3s, left 0.3s, right 0.3s"
          }}
        >
          {isOpen ? (
            <span className="icon-x">✕</span>
          ) : (
            <span className="icon-arrow">▶</span>
          )}
        </button>
        {isOpen && (
          <ul className="menu-list">
            <li><a href="#">Inicio</a></li>
            <li><a href="#">Suministros</a></li>
            <li><a href="#">Tiendas</a></li>
            <li><a href="#">Contacto</a></li>
          </ul>
        )}
      </nav>
      {!isOpen && (
        <button
          className="menu-toggle-btn open-btn"
          onClick={onToggle}
          aria-label="Abrir menú"
          style={{
            position: "fixed",
            top: 18,
            left: 0,
            zIndex: 200,
            transition: "top 0.3s, left 0.3s, right 0.3s"
          }}
        >
          <span className="icon-arrow">▶</span>
        </button>
      )}
    </>
  );
}

