.newsletter-error {
  color: #d32f2f;
  min-height: 24px;
  margin: 0;
  font-size: 0.98rem;
}

import React, { useState } from "react";
import "./MainContent.css";

export default function MainContent() {
    const [email, setEmail] = useState("");
    const [error, setError] = useState("");

    function validateEmail(email) {
        // Expresión regular simple para validar email
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    }

    function handleSubmit(e) {
        e.preventDefault();
        if (validateEmail(email)) {
            console.log("Correo enviado:", email);
            setEmail("");
            setError("");
        } else {
            setError("Introduce un correo electrónico válido.");
            alert("El correo no es válido");
        }
    }

    return (
        <div className="main-content">
            <h1>UNIR Supplies</h1>
            <p>Bienvenido a la plataforma de suministros para tiendas UNIR.</p>
            <p>Selecciona una opción en el menú para comenzar.</p>

            <form className="newsletter-form" onSubmit={handleSubmit} autoComplete="off">
                <label htmlFor="newsletter-email">Suscríbete a la newsletter:</label>
                <input
                    id="newsletter-email"
                    type="email"
                    placeholder="Tu correo electrónico"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                />
                <button type="submit">Enviar</button>
                <p className="newsletter-error">
                    {error}
                </p>
            </form>
        </div>
    );
}

import React, { useState } from "react";
import "./MainContent.css";

export default function MainContent() {
    const [email, setEmail] = useState("");
    const [error, setError] = useState("");

    function validateEmail(email) {
        // Expresión regular simple para validar email
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    }

    function handleChange(e) {
        const value = e.target.value;
        setEmail(value);
        if (value === "" || validateEmail(value)) {
            setError("");
        } else {
            setError("Introduce un correo electrónico válido.");
        }
    }

    function handleSubmit(e) {
        e.preventDefault();
        if (validateEmail(email)) {
            console.log("Correo enviado:", email);
            setEmail("");
            setError("");
        } else {
            setError("Introduce un correo electrónico válido.");
            alert("El correo no es válido");
        }
    }

    return (
        <div className="main-content">
            <h1>UNIR Supplies</h1>
            <p>Bienvenido a la plataforma de suministros para tiendas UNIR.</p>
            <p>Selecciona una opción en el menú para comenzar.</p>

            <form className="newsletter-form" onSubmit={handleSubmit} autoComplete="off">
                <label htmlFor="newsletter-email">Suscríbete a la newsletter:</label>
                <input
                    id="newsletter-email"
                    type="email"
                    placeholder="Tu correo electrónico"
                    value={email}
                    onChange={handleChange}
                />
                <button type="submit">Enviar</button>
                <p className="newsletter-error">
                    {error}
                </p>
            </form>
        </div>
    );
}

import React, { createContext, useContext, useState } from "react";

const GlobalContext = createContext();

export function GlobalProvider({ children }) {
  const [darkMode, setDarkMode] = useState(false);
  const toggleDarkMode = () => setDarkMode((v) => !v);

  return (
    <GlobalContext.Provider value={{ darkMode, toggleDarkMode }}>
      {children}
    </GlobalContext.Provider>
  );
}

export function useGlobalContext() {
  return useContext(GlobalContext);
}

.cart-container {
  position: fixed;
  top: 20px;
  right: 20px;
  z-index: 1000;
  transition: all 0.3s ease-in-out;
}

.cart-container.collapsed {
  width: 60px;
  height: 60px;
}

.cart-container.expanded {
  width: 350px;
  max-height: 500px;
  background: white;
  border-radius: 10px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  border: 1px solid #e0e0e0;
}

.cart-toggle {
  width: 60px;
  height: 60px;
  background: #389cd1;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  box-shadow: 0 2px 10px rgba(56, 156, 209, 0.3);
}

.cart-toggle:hover {
  background: #2a7bb8;
  transform: scale(1.05);
}

.cart-icon {
  font-size: 24px;
  color: white;
}

.cart-badge {
  position: absolute;
  top: -5px;
  right: -5px;
  background: #ff4757;
  color: white;
  border-radius: 50%;
  width: 20px;
  height: 20px;
  font-size: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
}

.cart-content {
  padding: 20px;
  max-height: 440px;
  overflow-y: auto;
}

.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  padding-bottom: 10px;
  border-bottom: 1px solid #e0e0e0;
}

.cart-header h3 {
  margin: 0;
  color: #333;
  font-size: 18px;
}

.close-cart {
  background: none;
  border: none;
  font-size: 24px;
  cursor: pointer;
  color: #666;
  padding: 0;
  width: 30px;
  height: 30px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  transition: all 0.2s ease;
}

.close-cart:hover {
  background: #f0f0f0;
  color: #333;
}

.cart-items {
  max-height: 300px;
  overflow-y: auto;
}

.empty-cart {
  text-align: center;
  padding: 40px 20px;
  color: #666;
}

.sad-face {
  font-size: 48px;
  margin-bottom: 10px;
}

.empty-cart p {
  margin: 0;
  font-size: 16px;
}

.cart-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 15px 0;
  border-bottom: 1px solid #f0f0f0;
}

.cart-item:last-child {
  border-bottom: none;
}

.cart-item-info h4 {
  margin: 0 0 5px 0;
  font-size: 14px;
  color: #333;
  font-weight: 600;
}

.cart-item-price {
  margin: 0;
  color: #389cd1;
  font-weight: bold;
  font-size: 14px;
}

.cart-item-controls {
  display: flex;
  align-items: center;
  gap: 8px;
}

.quantity-btn {
  background: #389cd1;
  color: white;
  border: none;
  width: 25px;
  height: 25px;
  border-radius: 50%;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: bold;
  transition: background 0.2s ease;
}

.quantity-btn:hover {
  background: #2a7bb8;
}

.quantity {
  min-width: 20px;
  text-align: center;
  font-weight: bold;
  color: #333;
}

.remove-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  padding: 2px;
  transition: transform 0.2s ease;
}

.remove-btn:hover {
  transform: scale(1.2);
}

.cart-total {
  margin-top: 20px;
  padding-top: 15px;
  border-top: 2px solid #389cd1;
  text-align: right;
  color: #333;
  font-size: 16px;
}

/* Animación para la expansión del carrito */
.cart-container.collapsed .cart-content {
  opacity: 0;
  visibility: hidden;
  transform: scale(0.8);
}

.cart-container.expanded .cart-content {
  opacity: 1;
  visibility: visible;
  transform: scale(1);
  transition: all 0.3s ease-in-out 0.1s;
}

.cart-container.expanded .cart-toggle {
  border-radius: 10px 10px 0 0;
  background: #389cd1;
  position: relative;
  z-index: 1;
}

/* Responsive */
@media (max-width: 768px) {
  .cart-container.expanded {
    width: 300px;
  }

  .cart-container {
    right: 10px;
    top: 10px;
  }
}

